refsection.programlisting:
source = imread(fullpath(getIPCVpath() + "/images/opencv_smarties.png"));
source = imresize(source, [240 320]);
reference = imread(fullpath(getIPCVpath() + "/images/opencv_fruits.jpg"));
reference = imresize(reference, [240 320]);
transferred = imcolortransfer(source, reference);
subplot(1, 3, 1);
imshow(source);
subplot(1, 3, 2);
imshow(reference);
subplot(1, 3, 3);
imshow(transferred);
